mapper.select:
SELECT B1.* FROM ( SELECT A1.* , ROW_NUMBER() OVER () AS PAGEINDEX FROM ( SELECT request.REQUEST_NO AS requestNo /* 요청번호 */ , request.REQUEST_NO AS requestOrgNo /* 요청번호 */ , requestMapping.OBJECT_NO AS documentNo /* 문서번호 */ , requestMapping.OBJECT_NM AS documentNm /* 문서명 */ , requestMapping.REV_NO AS revNo /* REV */ , FN_GET_CD_NM('requestPurpose', request.REQUEST_PURPOSE, #{sessionLang}) AS requestPurposeNm /* 용도 */ , CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = 'ko') WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = 'ko') ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = 'ko') END AS distributeTypeNm /* 배포유형 */ , companyUser.USER_CD AS companyUserCd /* 업체담당자 */ , companyUser.USER_NM AS companyUserNm /* 업체담당자 */ , ( SELECT USER_CD FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ORIGINAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS purchaserUserCd /* 구매담당자 */ , ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ORIGINAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS purchaserUserNm /* 구매담당자 */ , ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm /* 배포자 */ , request.INSERT_DT AS requestDt /* 요청일 */ , request.APPROVAL_DT AS approvalDt /* 승인일 */ , request.STATUS_CD AS statusCd /* 진행상태 */ , request.REQUEST_PURPOSE AS requestPurpose , FN_GET_CD_NM('requestStatusCd', request.STATUS_CD, #{sessionLang}) || '(' || ( SELECT COUNT(*) FROM DOCS_REQUEST_MAPPING tmp WHERE tmp.REQUEST_NO = request.REQUEST_NO ) || ')' AS statusNm /* 진행상태 */ , request.VENDOR_ACCEPT_YN AS vendorAcceptYn /* 업체접수여부 */ , FN_GET_CD_NM('vendorAcceptYn', request.VENDOR_ACCEPT_YN, #{sessionLang}) AS vendorAcceptNm /* 업체접수여부 */ , request.VENDOR_ACCEPT_USER_CD AS vendorAcceptUserCd /* 업체접수자 */ , (SELECT acceptUser.USER_NM FROM DOCS_USER acceptUser WHERE acceptUser.USER_CD = request.VENDOR_ACCEPT_USER_CD) AS vendorAcceptUserNm /* 업체접수자 */ , request.VENDOR_ACCEPT_DT AS vendorAcceptDt /* 업체접수일 */ FROM DOCS_REQUEST request INNER JOIN ( SELECT tempMapping.REQUEST_NO, MAX(tempMapping.OBJECT_ID) AS OBJECT_ID FROM DOCS_REQUEST_MAPPING tempMapping WHERE 1=1
AND OBJECT_NO LIKE '%' || UPPER(TRIM(#{documentNo})) || '%'
AND OBJECT_NM LIKE '%' || #{documentNm} || '%'
GROUP BY REQUEST_NO ) tempMapping ON tempMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = tempMapping.REQUEST_NO AND requestMapping.OBJECT_ID = tempMapping.OBJECT_ID INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD WHERE request.OBJECT_TYPE = 'DOC' AND request.REQUEST_TYPE = 'DISTRIBUTION' /* 배포요청만 표시 */ AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd} /* 로그인 한 사용자의 업체 정보만 표시 */
AND request.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
ORDER BY requestDt DESC, requestNo DESC
ORDER BY ${sortColumn} ${order}, requestNo ${order}
) A1 ) B1 WHERE 1=1
AND PAGEINDEX >= #{start}
AND PAGEINDEX <= #{end} ;

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT B1.* FROM ( SELECT A1.* FROM ( SELECT request.REQUEST_NO AS requestNo /* 요청번호 */ , request.REQUEST_NO AS requestOrgNo /* 요청번호 */ , requestMapping.OBJECT_NO AS documentNo /* 도면번호 */ , requestMapping.OBJECT_NM AS documentNm /* 도면명 */ , requestMapping.REV_NO AS revNo /* REV */ , request.REQUEST_PURPOSE AS requestPurpose /* 용도 */ , companyUser.USER_CD AS companyUserCd /* 업체담당자 */ , companyUser.USER_NM AS companyUserNm /* 업체담당자 */ , ( SELECT USER_CD FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ORIGINAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS purchaserUserCd /* 구매담당자 */ , ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ORIGINAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS purchaserUserNm /* 구매담당자 */ , ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm /* 배포자 */ , request.INSERT_DT AS requestDt /* 요청일 */ , request.APPROVAL_DT AS approvalDt /* 승인일 */ , request.STATUS_CD AS statusCd /* 진행상태 */ , request.VENDOR_ACCEPT_YN AS vendorAcceptYn /* 업체접수여부 */ , FN_GET_CD_NM('vendorAcceptYn', request.VENDOR_ACCEPT_YN, #{sessionLang}) AS vendorAcceptNm /* 업체접수여부 */ , request.VENDOR_ACCEPT_USER_CD AS vendorAcceptUserCd /* 업체접수자 */ , (SELECT acceptUser.USER_NM FROM DOCS_USER acceptUser WHERE acceptUser.USER_CD = request.VENDOR_ACCEPT_USER_CD) AS vendorAcceptUserNm /* 업체접수자 */ , request.VENDOR_ACCEPT_DT AS vendorAcceptDt /* 업체접수일 */ FROM DOCS_REQUEST request INNER JOIN ( SELECT tempMapping.REQUEST_NO, MAX(tempMapping.OBJECT_ID) AS OBJECT_ID FROM DOCS_REQUEST_MAPPING tempMapping WHERE 1=1
AND OBJECT_NO LIKE '%' || UPPER(TRIM(#{documentNo})) || '%'
AND OBJECT_NM LIKE '%' || #{documentNm} || '%'
GROUP BY REQUEST_NO ) tempMapping ON tempMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = tempMapping.REQUEST_NO AND requestMapping.OBJECT_ID = tempMapping.OBJECT_ID INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD WHERE request.OBJECT_TYPE = 'DOC' AND request.REQUEST_TYPE = 'DISTRIBUTION' /* 배포요청만 표시 */ AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd} /* 로그인 한 사용자의 업체 정보만 표시 */
AND request.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND purchaserUserCd = #{purchaserUserCd}
AND companyUserCd = #{companyUserCd}
AND statusCd = #{statusCd}
AND requestPurpose = #{requestPurpose}
) B1 ) C1
